import React, { type ReactNode } from 'react';
/**
 * Annotate part of the react tree with a product name
 * ```
 * <UFOLabel name="card">
 *   <Card card={data} />
 * </UFOLabel>
 * ```
 */
declare const UFOLabel: {
    (props: {
        name: string;
        children: ReactNode;
    }): React.JSX.Element;
    displayName: string;
};
export default UFOLabel;
